// Returns the icon spec for an extension, or null if no icon is available.
export function getLanguageIcon(ext) {
  if (!ext) return null;
  const name = EXT_TO_ICON[ext.toLowerCase()];
  if (!name) return null;
  return LANGUAGE_ICONS[name] || null;
}

// Returns the icon spec for a path (handling well-known extensionless
// filenames like Dockerfile / Makefile), or null.
export function getLanguageIconForPath(path) {
  if (!path) return null;
  const base = (path.split(/[\/]/).pop() || '').toLowerCase();
  if (base === 'dockerfile') return LANGUAGE_ICONS.docker;
  if (base === 'makefile') return LANGUAGE_ICONS.makefile;
  if (base === 'gemfile') return LANGUAGE_ICONS.ruby;
  if (base === 'cmakelists.txt') return LANGUAGE_ICONS.cmake;
  const ext = (path.split('.').pop() || '').toLowerCase();
  return getLanguageIcon(ext);
}

// Renders the language icon as an inline <svg>. extraClass is appended.
export function renderLanguageIcon(spec, extraClass = '') {
  if (!spec) return '';
  const extra = extraClass ? ` ${extraClass}` : '';
  return `<svg class="lang-icon${extra}" viewBox="${spec.viewBox}" xmlns="http://www.w3.org/2000/svg">${spec.inner}</svg>`;
}
